sections.css:
.bcn-phome {
  background: var(--color-surface);
  border-bottom: 1px solid var(--color-border);
}
.bcn-phome__cover {
  height: 132px;
  overflow: hidden;
  background: var(--color-surface-sunken);
}
.bcn-phome__hero {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.bcn-phome__body {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-500);
  padding: 0 var(--spacing-600) var(--spacing-500);
}
.bcn-phome__seal {
  flex-shrink: 0;
  width: 92px;
  height: 92px;
  margin-top: -46px;
  border-radius: var(--radius-full);
  background: var(--color-surface);
  border: 3px solid var(--color-surface);
  object-fit: contain;
  box-shadow: var(--shadow-100, 0 2px 12px 0 rgba(0, 0, 0, 0.08));
}
.bcn-phome__id {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
  padding-top: var(--spacing-400);
  min-width: 0;
  flex: 1;
}
.bcn-phome__idtop {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
  flex-wrap: wrap;
}
.bcn-phome__name {
  margin: 0;
  font-family: var(--font-decorative, var(--font-display, var(--font-sans)));
  font-weight: var(--font-weight-bold);
  font-size: var(--type-size-600);
  line-height: var(--line-height-tight);
  letter-spacing: var(--letter-spacing-tight);
  color: var(--bcn-gray-1000, var(--color-text-primary));
}
.bcn-phome__eyebrow {
  margin: 0 0 var(--spacing-200);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-tertiary);
}
.bcn-lrc {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.bcn-lrc__row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-300);
  padding: var(--spacing-250) 0;
  text-decoration: none;
  color: inherit;
}
.bcn-lrc__label {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
  min-width: 0;
}
.bcn-lrc__right {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-200);
  flex-shrink: 0;
}
.bcn-lrc li + li .bcn-lrc__row {
  border-top: 1px solid var(--color-border-light);
}
.bcn-lrc__meta {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.bcn-pf__desc {
  margin: 0 0 var(--spacing-300);
  font-size: var(--type-size-150);
  line-height: var(--line-height-normal);
  color: var(--color-text-secondary);
}
.bcn-pf {
  margin: 0;
  display: flex;
  flex-direction: column;
}
.bcn-pf__fact {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: var(--spacing-250) 0;
}
.bcn-pf__label {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-pf__value {
  margin: 0;
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-pf__fact + .bcn-pf__fact {
  border-top: 1px solid var(--color-border-light);
}
.bcn-crit {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-crit__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.bcn-crit__card {
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: var(--spacing-400);
  padding: var(--spacing-300) var(--spacing-400);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease,
    transform 0.15s ease;
}
.bcn-crit__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: var(--color-surface-sunken);
  color: var(--color-text-secondary);
}
.bcn-crit__body {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}
.bcn-crit__type {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-crit__title {
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-crit__where {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-crit__right {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: var(--spacing-100);
  flex-shrink: 0;
  text-align: right;
}
.bcn-crit__sev {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-150);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-crit__sev-dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_s);
  flex-shrink: 0;
}
.bcn-crit__timing {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  white-space: nowrap;
}
.bcn-crit__timing--late {
  color: var(--color-danger);
  font-weight: var(--font-weight-semibold);
}
.bcn-crit__code {
  display: inline-block;
  margin-right: var(--spacing-200);
  padding: 1px var(--spacing-150);
  font-family: var(--font-mono);
  font-size: 0.8125rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-commitment);
  background: color-mix(in srgb, var(--color-commitment) 12%, white);
  border-radius: var(--radius-100);
  vertical-align: 1px;
}
.bcn-stc {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-stc__head {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: var(--spacing-400);
  flex-wrap: wrap;
}
.bcn-stc__headings {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
  min-width: 0;
}
.bcn-stc__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-stc__lede {
  margin: 0;
  color: var(--color-text-secondary);
  max-width: 68ch;
}
.bcn-stc__all {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-100);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
  white-space: nowrap;
}
.bcn-stc__list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.bcn-stc__card {
  display: grid;
  grid-template-columns: minmax(0, 1.5fr) minmax(0, 1fr);
  align-items: center;
  gap: var(--spacing-500);
  padding: var(--spacing-400) var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease,
    transform 0.15s ease;
}
.bcn-stc__main {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  min-width: 0;
  padding-right: var(--spacing-500);
  border-right: 1px solid var(--color-border-light);
}
.bcn-stc__card-head {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-300);
}
.bcn-stc__glyph {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: color-mix(in srgb, var(--color-primary) 10%, var(--color-surface));
  color: var(--color-primary);
}
.bcn-stc__ident {
  min-width: 0;
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.bcn-stc__name {
  font-size: var(--type-size-250, 1.0625rem);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  line-height: var(--line-height-tight);
}
.bcn-stc__type {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-stc__headline {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
}
.bcn-stc__dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_c);
  flex-shrink: 0;
}
.bcn-stc__headline-text {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
}
.bcn-stc__pulse {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.bcn-stc__pulse-row {
  display: grid;
  grid-template-columns: auto 6rem 1fr;
  align-items: center;
  gap: var(--spacing-200);
  min-width: 0;
}
.bcn-stc__pulse-area {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-stc__pulse-note {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.bcn-tz {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
  padding: var(--spacing-500) var(--spacing-500) var(--spacing-600);
  background: color-mix(in srgb, var(--color-primary) 6%, var(--color-surface));
  border: 1px solid color-mix(in srgb, var(--color-primary) 18%, var(--color-surface));
  border-radius: var(--radius-400, var(--radius-300));
}
.bcn-tz__head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--spacing-400);
  flex-wrap: wrap;
}
.bcn-tz__headings {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  min-width: 0;
}
.bcn-tz__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-tz__summary {
  margin: 0;
  color: var(--color-text-secondary);
  max-width: 62ch;
}
.bcn-tz__cols {
  display: grid;
  grid-template-columns: minmax(0, 1.6fr) minmax(0, 1fr);
  gap: var(--spacing-500);
  align-items: start;
}
.bcn-tz__rollup {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
}
.bcn-tz__label {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-tz__stats {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-500) var(--spacing-600);
}
.bcn-tz__scope {
  margin: 0;
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-tz__sublinks {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-300) var(--spacing-500);
  padding-top: var(--spacing-400);
  border-top: 1px solid var(--color-border-light);
}
.bcn-tz__sublink {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-100);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
}
.bcn-tz__sublink .esa-icon {
  color: var(--color-text-muted);
}
.bcn-sd {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-sd__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-sd__grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));
  gap: var(--spacing-400);
}
.bcn-sd__card {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-400);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease;
}
.bcn-sd__head {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
}
.bcn-sd__glyph {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: var(--color-surface-sunken);
  color: var(--color-text-secondary);
}
.bcn-sd__name {
  font-size: var(--type-size-300);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-sd__summary {
  margin: 0;
  font-size: var(--type-size-150);
  color: var(--color-text-secondary);
  line-height: var(--line-height-normal);
}
.bcn-sd__rollup {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-300) var(--spacing-500);
  margin: 0;
  padding: var(--spacing-300) 0;
  border-top: 1px solid var(--color-border-light);
  border-bottom: 1px solid var(--color-border-light);
  --stat-value-size: var(--type-size-400);
  --stat-label-size: var(--type-size-150);
  --stat-label-color: var(--color-text-tertiary);
}
.bcn-sd__flag {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-200);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.bcn-sd__dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_c);
  flex-shrink: 0;
}
.bcn-sd__open {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-100);
  margin-top: auto;
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
}
.bcn-sd__glyph--wizard {
  border-radius: var(--radius-full);
  background: var(--bcn-teal-600, var(--color-secondary));
  color: var(--color-text-inverse);
}
.bcn-sd__name--serif {
  font-family: var(--font-decorative, var(--font-sans));
  font-weight: var(--font-weight-bold);
}
.page-layout {
  display: flex;
  flex-direction: column;
  min-height: calc(100vh - 52px);
  padding: var(--spacing-600);
  background: var(--bcn-gray-50);
  box-sizing: border-box;
}
.page-layout--bleed {
  padding: 0;
}
.page-layout__bleed {
  width: 100%;
}
.page-layout__container {
  display: flex;
  flex-direction: column;
}
.page-layout--bleed .page-layout__container {
  padding: 0 var(--spacing-600) var(--spacing-600);
}
.page-layout__content {
  padding: var(--spacing-500) 0;
  min-height: 70vh;
  position: relative;
}
.page-layout section {
  width: 100%;
}
.esa-button {
  --_btn-height: var(--form-height-md, 40px);
  --_btn-padding-x: var(--form-padding-x-md, 16px);
  --_btn-font-size: var(--form-font-size-md, 14px);
  --_btn-radius: var(--form-radius-md, 6px);
  --_accent: var(--color-primary, #46a758);
  --_accent-hover: var(--color-primary-hover, #3e9b4f);
  --_on: var(--color-text-inverse, #ffffff);
  --_accent-text: var(--_accent);
  --_btn-tint-hover: color-mix(in srgb, var(--_accent) 8%, transparent);
  --_btn-tint-active: color-mix(in srgb, var(--_accent) 14%, transparent);
  display: inline-block;
}
.esa-button--color-primary {
  --_accent-text: var(--color-primary-strong);
}
.esa-button__native {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-200, 8px);
  width: 100%;
  height: var(--_btn-height);
  padding-inline: var(--_btn-padding-x);
  border: 1px solid transparent;
  border-radius: var(--_btn-radius);
  font-size: var(--_btn-font-size);
  font-family: var(--font-sans, system-ui, sans-serif);
  font-weight: var(--font-weight-medium, 500);
  line-height: 1;
  text-decoration: none;
  cursor: pointer;
  transition:
    background var(--transition-fast, 0.15s ease),
    border-color var(--transition-fast, 0.15s ease);
  -webkit-appearance: none;
  appearance: none;
}
.esa-button--appearance-fill .esa-button__native {
  background: var(--_accent);
  color: var(--_on);
  border-color: transparent;
}
.esa-button__label {
  white-space: nowrap;
}
.bcn-status-chip {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-150);
  padding: 2px var(--spacing-250);
  border-radius: var(--radius-full);
  font-size: var(--type-size-100);
  font-weight: var(--font-weight-semibold);
  white-space: nowrap;
  background: color-mix(in srgb, var(--_chip) 16%, transparent);
  color: color-mix(in srgb, var(--_chip) 72%, #1a1a1a);
}
.bcn-status-chip__dot {
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  background: var(--_chip);
  flex-shrink: 0;
}
.esa-card {
  --_card-bg: var(--card-bg, var(--color-surface, #ffffff));
  --_card-border: var(--card-border-color, var(--color-border, #e5e5e5));
  --_card-radius: var(--card-radius, var(--radius-300, 0.5rem));
  --_card-padding: var(--card-padding, var(--spacing-500, 1.5rem));
  --_card-header-bg: var(--card-header-bg, transparent);
  --_card-header-color: var(--card-header-color, var(--color-text-primary, #171717));
  --_card-header-border: var(--card-header-border-color, var(--color-border-light, #efefef));
  display: block;
  background: var(--_card-bg);
  border: 1px solid var(--_card-border);
  border-radius: var(--_card-radius);
  overflow: hidden;
}
.esa-card__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-400, 1rem) var(--_card-padding);
  background: var(--_card-header-bg);
  color: var(--_card-header-color);
  border-bottom: 1px solid var(--_card-header-border);
  min-height: 56px;
}
.esa-card__header-content {
  display: flex;
  align-items: center;
  gap: var(--spacing-300, 0.75rem);
}
.esa-card__titles {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-050, 0.125rem);
}
.esa-card__title {
  font-size: var(--type-size-250, 1.0625rem);
  font-weight: 600;
  margin: 0;
  color: inherit;
  font-family: var(--font-sans, "DM Sans", sans-serif);
}
.esa-card__actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-200, 0.5rem);
}
.esa-card__body {
  padding: var(--_card-padding);
}
.bcn-count {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  height: 18px;
  padding: 0 var(--spacing-100);
  font-size: 0.8125rem;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-100);
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.sidebar {
  --gap: var(--spacing-500, 1.5rem);
  --sidebar-width: 18rem;
  --sidebar-content-min: 60%;
  display: flex;
  flex-wrap: wrap;
  gap: var(--gap);
}
.stack {
  --gap: var(--spacing-400, 1rem);
  display: flex;
  flex-direction: column;
  gap: var(--gap);
}
.sidebar > :first-child {
  flex-basis: var(--sidebar-width);
  flex-grow: 1;
}
.sidebar[data-side="end"] > :first-child {
  order: 2;
}
.sidebar > :last-child {
  flex-basis: 0;
  flex-grow: 999;
  min-inline-size: var(--sidebar-content-min);
}
.type-section-title {
  font-family: var(--font-display, var(--font-sans));
  font-size: var(--type-size-500);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-tight);
  letter-spacing: var(--letter-spacing-tight);
}
.type-body-small {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-regular);
  line-height: var(--line-height-normal);
  letter-spacing: var(--letter-spacing-normal);
}
