  padding: 0;
  border: 0;
  border-radius: var(--radius-200, 8px);
  background: transparent;
  color: inherit;
  cursor: pointer;
  transition: background var(--transition-fast, 0.15s ease);
  -webkit-appearance: none;
  appearance: none;
}
.esa-stat {
  --_stat-value-color: var(--stat-value-color, var(--color-text-primary, #171717));
  --_stat-value-font: var(
    --stat-value-font,
    var(--font-display, var(--font-sans, "DM Sans", sans-serif))
  );
  --_stat-value-size: var(--stat-value-size, var(--type-size-700, 2.25rem));
  --_stat-value-weight: var(--stat-value-weight, var(--font-weight-bold, 650));
  --_stat-label-color: var(--stat-label-color, var(--color-text-secondary, #525252));
  --_stat-label-size: var(--stat-label-size, var(--type-size-200, 0.9375rem));
  --_stat-label-weight: var(--stat-label-weight, var(--font-weight-medium, 450));
  --_stat-sub-color: var(--stat-sub-color, var(--color-text-muted, #737373));
  --_stat-sub-size: var(--stat-sub-size, var(--type-size-150, 0.875rem));
  --_stat-accent-color: var(--stat-accent-color, var(--color-secondary-strong, #3a7c59));
  --_stat-gap: var(--stat-gap, var(--spacing-050, 0.125rem));
  display: flex;
  flex-direction: column;
  gap: var(--_stat-gap);
  background: transparent;
}
.esa-stat__value {
  font-family: var(--_stat-value-font);
  font-size: var(--_stat-value-size);
  font-weight: var(--_stat-value-weight);
  line-height: var(--line-height-tight, 1.3);
  letter-spacing: var(--letter-spacing-tight, -0.01em);
  color: var(--_stat-value-color);
}
.esa-stat__label {
  font-size: var(--_stat-label-size);
  font-weight: var(--_stat-label-weight);
  line-height: var(--line-height-normal, 1.6);
  color: var(--_stat-label-color);
}

full.css:
:root,
[data-theme="beacon"] {
  --bcn-aldo: #08908b;
  --bcn-aldo-100: #cfeceb;
  --bcn-aldo-50: #e8f6f5;
  --bcn-gray-100: #efefef;
  --bcn-gray-1000: #000000;
  --bcn-gray-200: #dcdcdc;
  --bcn-gray-300: #bdbdbd;
  --bcn-gray-400: #989898;
  --bcn-gray-50: #fafafa;
  --bcn-gray-500: #7c7c7c;
  --bcn-gray-600: #656565;
  --bcn-gray-900: #3d3d3d;
  --bcn-gray-950: #292929;
  --bcn-helpbar-bg: rgba(23, 25, 27, 0.78);
  --bcn-helpbar-bg-solid: #1f2224;
  --bcn-helpbar-border: rgba(255, 255, 255, 0.12);
  --bcn-helpbar-divider: rgba(255, 255, 255, 0.16);
  --bcn-helpbar-fg: rgba(255, 255, 255, 0.92);
  --bcn-helpbar-fg-muted: rgba(255, 255, 255, 0.72);
  --bcn-helpbar-hover-bg: rgba(255, 255, 255, 0.1);
  --bcn-teal-600: #0e807b;
  --card-bg: #fcfcfc;
  --card-border-color: #dcdcdc;
  --card-header-bg: transparent;
  --card-header-border-color: #efefef;
  --card-header-color: #3d3d3d;
  --card-padding: 1.5rem;
  --card-radius: 0.5rem;
  --color-accent: #f76b15;
  --color-border: #dcdcdc;
  --color-border-light: #efefef;
  --color-commitment: #58508d;
  --color-danger: #e5484d;
  --color-primary: #005862;
  --color-primary-hover: #00474f;
  --color-primary-strong: #2a7e3b;
  --color-secondary: #00918b;
  --color-secondary-strong: #2a7e3b;
  --color-surface: #fcfcfc;
  --color-surface-sunken: #efefef;
  --color-text-inverse: #fcfcfc;
  --color-text-link: #005862;
  --color-text-muted: #7c7c7c;
  --color-text-primary: #3d3d3d;
  --color-text-secondary: #525252;
  --color-text-tertiary: #656565;
  --font-decorative: "Besley", serif;
  --font-display: "DM Sans", sans-serif;
  --font-mono: "Roboto Mono", ui-monospace, monospace;
  --font-sans: "DM Sans", sans-serif;
  --font-weight-bold: 650;
  --font-weight-medium: 450;
  --font-weight-regular: 350;
  --font-weight-semibold: 550;
  --form-font-size-md: clamp(0.75rem, 0.66rem + 0.44vw, 0.9375rem);
  --form-height-md: 36px;
  --form-padding-x-md: 0.75rem;
  --form-radius-md: 0.25rem;
  --icon-button-bg-hover: color-mix(in srgb, currentColor 14%, transparent);
  --icon-size-md: 20px;
  --icon-size-medium: 20px;
  --icon-size-sm: 16px;
  --icon-size-small: 16px;
  --icon-size-xs: 14px;
  --letter-spacing-normal: 0.01em;
  --letter-spacing-tight: -0.01em;
  --line-height-normal: 1.6;
  --line-height-relaxed: 1.8;
  --line-height-tight: 1.3;
  --popover-bg: #fcfcfc;
  --popover-border-color: #dcdcdc;
  --popover-color: #3d3d3d;
  --popover-radius: 0.5rem;
  --radius-100: 0.25rem;
  --radius-200: 0.5rem;
  --radius-300: 0.5rem;
  --radius-400: 0.75rem;
  --radius-full: 9999px;
  --shadow-100: 0 2px 12px 0 rgba(0, 0, 0, 0.04);
  --shadow-300: 0 6px 24px -6px rgba(0, 0, 0, 0.07);
  --side-dialog-width: 400px;
  --sidebar-width: 280px;
  --spacing-050: 0.125rem;
  --spacing-100: 0.25rem;
  --spacing-150: 0.375rem;
  --spacing-200: 0.5rem;
  --spacing-250: 0.625rem;
  --spacing-300: 0.75rem;
  --spacing-400: 1rem;
  --spacing-500: 1.5rem;
  --spacing-600: 2rem;
  --spacing-700: 3rem;
  --transition-fast: 0.15s ease;
  --type-size-100: clamp(0.625rem, 0.56rem + 0.32vw, 0.75rem);
  --type-size-150: clamp(0.6875rem, 0.61rem + 0.38vw, 0.875rem);
  --type-size-200: clamp(0.75rem, 0.66rem + 0.44vw, 0.9375rem);
  --type-size-250: clamp(0.8125rem, 0.71rem + 0.5vw, 1.0625rem);
  --type-size-300: clamp(0.875rem, 0.77rem + 0.52vw, 1.125rem);
  --type-size-400: clamp(1rem, 0.88rem + 0.6vw, 1.25rem);
  --type-size-500: clamp(1.125rem, 0.98rem + 0.72vw, 1.5rem);
  --type-size-600: clamp(1.375rem, 1.2rem + 0.88vw, 1.875rem);
  --type-size-700: clamp(1.625rem, 1.41rem + 1.08vw, 2.25rem);
}

:host {
  --_width: var(--side-dialog-width, 400px);
}
.bcn-phome {
  background: var(--color-surface);
  border-bottom: 1px solid var(--color-border);
}
.bcn-phome__cover {
  height: 132px;
  overflow: hidden;
  background: var(--color-surface-sunken);
}
.bcn-phome__hero {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
}
.bcn-phome__body {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-500);
  padding: 0 var(--spacing-600) var(--spacing-500);
}
.bcn-phome__seal {
  flex-shrink: 0;
  width: 92px;
  height: 92px;
  margin-top: -46px;
  border-radius: var(--radius-full);
  background: var(--color-surface);
  border: 3px solid var(--color-surface);
  object-fit: contain;
  box-shadow: var(--shadow-100, 0 2px 12px 0 rgba(0, 0, 0, 0.08));
}
.bcn-phome__id {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
  padding-top: var(--spacing-400);
  min-width: 0;
  flex: 1;
}
.bcn-phome__idtop {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
  flex-wrap: wrap;
}
.bcn-phome__name {
  margin: 0;
  font-family: var(--font-decorative, var(--font-display, var(--font-sans)));
  font-weight: var(--font-weight-bold);
  font-size: var(--type-size-600);
  line-height: var(--line-height-tight);
  letter-spacing: var(--letter-spacing-tight);
  color: var(--bcn-gray-1000, var(--color-text-primary));
}
.bcn-phome__eyebrow {
  margin: 0 0 var(--spacing-200);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-tertiary);
}
.bcn-lrc {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
}
.bcn-lrc__row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-300);
  padding: var(--spacing-250) 0;
  text-decoration: none;
  color: inherit;
}
.bcn-lrc__label {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
  min-width: 0;
}
.bcn-lrc__right {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-200);
  flex-shrink: 0;
}
.bcn-lrc li + li .bcn-lrc__row {
  border-top: 1px solid var(--color-border-light);
}
.bcn-lrc__meta {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}
.bcn-pf__desc {
  margin: 0 0 var(--spacing-300);
  font-size: var(--type-size-150);
  line-height: var(--line-height-normal);
  color: var(--color-text-secondary);
}
.bcn-pf {
  margin: 0;
  display: flex;
  flex-direction: column;
}
.bcn-pf__fact {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: var(--spacing-250) 0;
}
.bcn-pf__label {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-pf__value {
  margin: 0;
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-pf__fact + .bcn-pf__fact {
  border-top: 1px solid var(--color-border-light);
}
.bcn-crit {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-crit__list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.bcn-crit__card {
  display: grid;
  grid-template-columns: auto 1fr auto;
  align-items: center;
  gap: var(--spacing-400);
  padding: var(--spacing-300) var(--spacing-400);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease,
    transform 0.15s ease;
}
.bcn-crit__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: var(--color-surface-sunken);
  color: var(--color-text-secondary);
}
.bcn-crit__body {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}
.bcn-crit__type {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-crit__title {
  font-size: var(--type-size-200);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-crit__where {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-crit__right {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: var(--spacing-100);
  flex-shrink: 0;
  text-align: right;
}
.bcn-crit__sev {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-150);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-crit__sev-dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_s);
  flex-shrink: 0;
}
.bcn-crit__timing {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  white-space: nowrap;
}
.bcn-crit__timing--late {
  color: var(--color-danger);
  font-weight: var(--font-weight-semibold);
}
.bcn-crit__code {
  display: inline-block;
  margin-right: var(--spacing-200);
  padding: 1px var(--spacing-150);
  font-family: var(--font-mono);
  font-size: 0.8125rem;
  font-weight: var(--font-weight-semibold);
  color: var(--color-commitment);
  background: color-mix(in srgb, var(--color-commitment) 12%, white);
  border-radius: var(--radius-100);
  vertical-align: 1px;
}
.bcn-stc {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-stc__head {
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: var(--spacing-400);
  flex-wrap: wrap;
}
.bcn-stc__headings {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-100);
  min-width: 0;
}
.bcn-stc__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-stc__lede {
  margin: 0;
  color: var(--color-text-secondary);
  max-width: 68ch;
}
.bcn-stc__all {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-100);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
  white-space: nowrap;
}
.bcn-stc__list {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
}
.bcn-stc__card {
  display: grid;
  grid-template-columns: minmax(0, 1.5fr) minmax(0, 1fr);
  align-items: center;
  gap: var(--spacing-500);
  padding: var(--spacing-400) var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease,
    transform 0.15s ease;
}
.bcn-stc__main {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  min-width: 0;
  padding-right: var(--spacing-500);
  border-right: 1px solid var(--color-border-light);
}
.bcn-stc__card-head {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-300);
}
.bcn-stc__glyph {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: color-mix(in srgb, var(--color-primary) 10%, var(--color-surface));
  color: var(--color-primary);
}
.bcn-stc__ident {
  min-width: 0;
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.bcn-stc__name {
  font-size: var(--type-size-250, 1.0625rem);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
  line-height: var(--line-height-tight);
}
.bcn-stc__type {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-stc__headline {
  display: flex;
  align-items: center;
  gap: var(--spacing-200);
}
.bcn-stc__dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_c);
  flex-shrink: 0;
}
.bcn-stc__headline-text {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
}
.bcn-stc__pulse {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-200);
}
.bcn-stc__pulse-row {
  display: grid;
  grid-template-columns: auto 6rem 1fr;
  align-items: center;
  gap: var(--spacing-200);
  min-width: 0;
}
.bcn-stc__pulse-area {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-stc__pulse-note {
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}
.bcn-tz {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-500);
  padding: var(--spacing-500) var(--spacing-500) var(--spacing-600);
  background: color-mix(in srgb, var(--color-primary) 6%, var(--color-surface));
  border: 1px solid color-mix(in srgb, var(--color-primary) 18%, var(--color-surface));
  border-radius: var(--radius-400, var(--radius-300));
}
.bcn-tz__head {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: var(--spacing-400);
  flex-wrap: wrap;
}
.bcn-tz__headings {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-150);
  min-width: 0;
}
.bcn-tz__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-tz__summary {
  margin: 0;
  color: var(--color-text-secondary);
  max-width: 62ch;
}
.bcn-tz__cols {
  display: grid;
  grid-template-columns: minmax(0, 1.6fr) minmax(0, 1fr);
  gap: var(--spacing-500);
  align-items: start;
}
.bcn-tz__rollup {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-500);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
}
.bcn-tz__label {
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-secondary);
}
.bcn-tz__stats {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-500) var(--spacing-600);
}
.bcn-tz__scope {
  margin: 0;
  font-size: var(--type-size-150);
  color: var(--color-text-tertiary);
}
.bcn-tz__sublinks {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-300) var(--spacing-500);
  padding-top: var(--spacing-400);
  border-top: 1px solid var(--color-border-light);
}
.bcn-tz__sublink {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-100);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary);
}
.bcn-tz__sublink .esa-icon {
  color: var(--color-text-muted);
}
.bcn-sd {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-400);
}
.bcn-sd__title {
  margin: 0;
  color: var(--color-text-primary);
}
.bcn-sd__grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(16rem, 1fr));
  gap: var(--spacing-400);
}
.bcn-sd__card {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-300);
  padding: var(--spacing-400);
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-300);
  text-decoration: none;
  color: inherit;
  transition:
    border-color 0.15s ease,
    box-shadow 0.15s ease;
}
.bcn-sd__head {
  display: flex;
  align-items: center;
  gap: var(--spacing-300);
}
.bcn-sd__glyph {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  flex-shrink: 0;
  border-radius: var(--radius-200);
  background: var(--color-surface-sunken);
  color: var(--color-text-secondary);
}
.bcn-sd__name {
  font-size: var(--type-size-300);
  font-weight: var(--font-weight-semibold);
  color: var(--color-text-primary);
}
.bcn-sd__summary {
  margin: 0;
  font-size: var(--type-size-150);
  color: var(--color-text-secondary);
  line-height: var(--line-height-normal);
}
.bcn-sd__rollup {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-300) var(--spacing-500);
  margin: 0;
  padding: var(--spacing-300) 0;
  border-top: 1px solid var(--color-border-light);
  border-bottom: 1px solid var(--color-border-light);
  --stat-value-size: var(--type-size-400);
  --stat-label-size: var(--type-size-150);
  --stat-label-color: var(--color-text-tertiary);
}
.bcn-sd__flag {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-200);
  font-size: var(--type-size-150);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-secondary);
}
.bcn-sd__dot {
  width: 9px;
  height: 9px;
  border-radius: var(--radius-full);
  background: var(--_c);
